#include<bits/stdc++.h>
using namespace std;
int m,q,res[100005];
char S[2000005];
int read(int s,int &x){x=0;
	while(isdigit(S[s]))x=x*10+(S[s]-'0'),++s;
	return s;
}int brdg(int s,int l,int r){
	if(isdigit(S[s])){
		int tmp,ret=read(s,tmp);
		for(int i=l;i<=r;i++)res[i]=tmp;
		return ret;
	}int sep;int stt=read(s+2,sep);
	if(S[s+1]=='>'){
		int neg=brdg(stt+1,sep+1,r);
		return brdg(neg+1,l,sep);
	}else{
		int neg=brdg(stt+1,l,sep-1);
		return brdg(neg+1,sep,r);
	}
}
int main(void){
	scanf("%d%d%s",&m,&q,S);
	brdg(0,1,m+1);
	for(int x;q;q--){
		scanf("%d",&x);
		printf("%d\n",res[min(x,m+1)]);
	}
	return false;
}
